/* ui/js/chat/modules/warnings.js */
// warnings.js — System Warnings UI module
// Loads warnings from /api/warnings, renders the modal, and listens for SSE updates.
//
// Badge behaviour:
//   RED  + blink  — one or more warnings whose IDs have never been acknowledged
//   GRAY + no blink — all current warnings were previously acknowledged (known issues)
//   hidden          — no warnings at all
//
// Acknowledged IDs are persisted in localStorage so the state survives page reloads
// and server restarts. Only truly NEW warning IDs cause the red/blink state again.

(function () {
    'use strict';

    const btn = document.getElementById('warnings-btn');
    const badge = document.getElementById('warnings-badge');
    const overlay = document.getElementById('warnings-overlay');
    const listEl = document.getElementById('warnings-list');
    const closeBtn = document.getElementById('warnings-close');
    const ackAllBtn = document.getElementById('warnings-ack-all');

    if (!btn || !overlay) return;

    let warningsData = [];
    let blinkInterval = null;

    // ── localStorage persistence ──────────────────────────────
    const LS_KEY = 'aurago-warnings-acked';

    function getAckedIds() {
        try {
            return new Set(JSON.parse(localStorage.getItem(LS_KEY) || '[]'));
        } catch (e) {
            return new Set();
        }
    }

    function persistAckedId(id) {
        const set = getAckedIds();
        set.add(id);
        try { localStorage.setItem(LS_KEY, JSON.stringify([...set])); } catch (e) {}
    }

    function persistAckedIds(warnings) {
        const set = getAckedIds();
        warnings.forEach(function (w) { set.add(w.id); });
        try { localStorage.setItem(LS_KEY, JSON.stringify([...set])); } catch (e) {}
    }

    // ── Severity helpers ──────────────────────────────────────
    function severityIcon(sev) {
        const markup = window.chatUiIconMarkup || (() => '');
        switch (sev) {
            case 'critical': return markup('error');
            case 'warning':  return markup('warning');
            default:         return markup('info');
        }
    }

    function severityOrder(sev) {
        switch (sev) {
            case 'critical': return 0;
            case 'warning':  return 1;
            default:         return 2;
        }
    }

    // ── Badge / blink ─────────────────────────────────────────
    // warnings: full array from server.
    function updateBadge(warnings) {
        const total = warnings.length;
        if (total === 0) {
            badge.classList.add('is-hidden');
            badge.classList.remove('seen');
            stopBlink();
            return;
        }

        const ackedIds = getAckedIds();
        // "New" = present on server AND never acknowledged by this user
        const newCount = warnings.filter(function (w) { return !ackedIds.has(w.id); }).length;

        if (newCount > 0) {
            // Genuinely new problems — alert the user
            badge.textContent = newCount;
            badge.classList.remove('is-hidden', 'seen');
            startBlink();
        } else {
            // All problems are known / previously acknowledged — show softly
            badge.textContent = total;
            badge.classList.remove('is-hidden');
            badge.classList.add('seen');
            stopBlink();
        }
    }

    function startBlink() {
        if (blinkInterval) return;
        blinkInterval = setInterval(function () {
            btn.classList.toggle('warnings-blink');
        }, 800);
    }

    function stopBlink() {
        if (blinkInterval) {
            clearInterval(blinkInterval);
            blinkInterval = null;
        }
        btn.classList.remove('warnings-blink');
    }

    // ── Render ────────────────────────────────────────────────
    function renderWarnings() {
        listEl.innerHTML = '';
        if (warningsData.length === 0) {
            const empty = document.createElement('div');
            empty.className = 'warnings-empty';
            empty.textContent = typeof t === 'function' ? t('chat.warnings_empty') : 'No active warnings.';
            listEl.appendChild(empty);
            return;
        }

        const ackedIds = getAckedIds();

        // Sort: new (unacked locally) first, then critical > warning > info, then by timestamp desc
        warningsData.sort(function (a, b) {
            const aNew = !ackedIds.has(a.id);
            const bNew = !ackedIds.has(b.id);
            if (aNew !== bNew) return aNew ? -1 : 1;
            const so = severityOrder(a.severity) - severityOrder(b.severity);
            if (so !== 0) return so;
            return new Date(b.timestamp) - new Date(a.timestamp);
        });

        warningsData.forEach(function (w) {
            const isLocallyAcked = ackedIds.has(w.id);
            const item = document.createElement('div');
            item.className = 'warnings-item' + (isLocallyAcked ? ' acknowledged' : '');
            item.dataset.id = w.id;

            const header = document.createElement('div');
            header.className = 'warnings-item-header';

            const left = document.createElement('span');
            left.innerHTML = severityIcon(w.severity) + ' <strong>' + escapeHtml(w.title) + '</strong>';

            const right = document.createElement('span');
            right.className = 'warnings-item-meta';
            const catLabel = typeof t === 'function' ? t('chat.warnings_cat_' + w.category) || w.category : w.category;
            right.textContent = catLabel;
            if (isLocallyAcked) {
                right.insertAdjacentHTML('beforeend', ' ' + (window.chatUiIconMarkup ? window.chatUiIconMarkup('complete') : ''));
            }

            header.appendChild(left);
            header.appendChild(right);
            item.appendChild(header);

            const desc = document.createElement('div');
            desc.className = 'warnings-item-desc';
            desc.textContent = w.description;
            item.appendChild(desc);

            if (!isLocallyAcked) {
                const ackBtn = document.createElement('button');
                ackBtn.className = 'btn-small warnings-ack-btn';
                ackBtn.textContent = typeof t === 'function' ? t('chat.warnings_acknowledge') : 'Acknowledge';
                ackBtn.addEventListener('click', function () {
                    acknowledgeWarning(w.id);
                });
                item.appendChild(ackBtn);
            }

            listEl.appendChild(item);
        });
    }

    function escapeHtml(str) {
        const d = document.createElement('div');
        d.textContent = str;
        return d.innerHTML;
    }

    // ── API calls ─────────────────────────────────────────────
    function loadWarnings() {
        fetch('/api/warnings', { credentials: 'same-origin' })
            .then(function (r) { return r.json(); })
            .then(function (data) {
                warningsData = data.warnings || [];
                updateBadge(warningsData);
                if (overlay.classList.contains('active')) {
                    renderWarnings();
                }
            })
            .catch(function (err) {
                console.warn('[Warnings] fetch failed:', err);
            });
    }

    function acknowledgeWarning(id) {
        // Persist locally first so the badge updates instantly even if the server call is slow
        persistAckedId(id);
        updateBadge(warningsData);
        renderWarnings();

        fetch('/api/warnings/acknowledge', {
            method: 'POST',
            credentials: 'same-origin',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ id: id })
        })
            .then(function () { loadWarnings(); })
            .catch(function (err) { console.warn('[Warnings] ack failed:', err); });
    }

    function acknowledgeAll() {
        // Persist all current IDs locally
        persistAckedIds(warningsData);
        updateBadge(warningsData);
        renderWarnings();

        fetch('/api/warnings/acknowledge', {
            method: 'POST',
            credentials: 'same-origin',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ all: true })
        })
            .then(function () { loadWarnings(); })
            .catch(function (err) { console.warn('[Warnings] ack-all failed:', err); });
    }

    // ── Modal toggle ──────────────────────────────────────────
    function openWarnings() {
        renderWarnings();
        overlay.classList.add('active');
    }

    function closeWarnings() {
        overlay.classList.remove('active');
    }

    btn.addEventListener('click', function () {
        if (overlay.classList.contains('active')) {
            closeWarnings();
        } else {
            loadWarnings();
            openWarnings();
        }
    });

    closeBtn.addEventListener('click', closeWarnings);
    ackAllBtn.addEventListener('click', acknowledgeAll);

    overlay.addEventListener('click', function (e) {
        if (e.target === overlay) closeWarnings();
    });

    // ── SSE listener ──────────────────────────────────────────
    if (typeof AuraSSE !== 'undefined') {
        AuraSSE.on('system_warning', function (payload) {
            // Reload full list to stay in sync
            loadWarnings();
        });
    }

    // ── Initial load ──────────────────────────────────────────
    loadWarnings();
})();

;
/* ui/js/chat/modules/session-drawer.js */
/* ── Session Drawer Module ────────────────────────────────────────────────────
 * Manages the chat session list, creation, switching, and deletion.
 * Exposes a global `window.SessionDrawer` object used by main.js.
 * ──────────────────────────────────────────────────────────────────────────── */

window.SessionDrawer = (function () {
    'use strict';

    // ── State ──
    let activeSessionId = localStorage.getItem('aurago-session-id') || 'default';
    let sessions = [];
    let isOpen = false;

    // ── DOM refs ──
    const drawer = document.getElementById('session-drawer');
    const backdrop = document.getElementById('session-backdrop');
    const listEl = document.getElementById('session-list');
    const toggleBtn = document.getElementById('session-toggle-btn');
    const closeBtn = document.getElementById('session-drawer-close');
    const newBtn = document.getElementById('session-new-btn');

    // ── Helpers ──
    function t(key) {
        return typeof I18N !== 'undefined' && I18N[key] ? I18N[key] : key;
    }

    function escapeHtml(str) {
        const div = document.createElement('div');
        div.textContent = str;
        return div.innerHTML;
    }

    function escapeAttr(str) {
        return String(str).replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/'/g, '&#39;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    }

    function parseDate(dateStr) {
        if (!dateStr) return null;
        // Strategy 1: Already valid ISO 8601 / RFC3339
        let d = new Date(dateStr);
        if (!isNaN(d.getTime())) return d;
        // Strategy 2: SQLite format "2006-01-02 15:04:05" → add T and Z
        d = new Date(dateStr.replace(' ', 'T') + 'Z');
        if (!isNaN(d.getTime())) return d;
        // Strategy 3: SQLite format without Z
        d = new Date(dateStr.replace(' ', 'T'));
        if (!isNaN(d.getTime())) return d;
        // Strategy 4: Replace space with T, keep existing timezone info
        d = new Date(dateStr.replace(' ', 'T').replace(/(\d{2}:\d{2}:\d{2})$/, '$1Z'));
        if (!isNaN(d.getTime())) return d;
        return null;
    }

    function formatTimeAgo(dateStr) {
        if (!dateStr) return '';
        try {
            const date = parseDate(dateStr);
            if (!date) return dateStr;
            const now = new Date();
            const diffMs = now - date;
            const diffMin = Math.floor(diffMs / 60000);
            if (diffMin < 1) return t('chat.sessions_just_now');
            if (diffMin < 60) return t('chat.sessions_minutes_ago').replace('{n}', diffMin);
            const diffH = Math.floor(diffMin / 60);
            if (diffH < 24) return t('chat.sessions_hours_ago').replace('{n}', diffH);
            const diffD = Math.floor(diffH / 24);
            if (diffD < 7) return t('chat.sessions_days_ago').replace('{n}', diffD);
            return date.toLocaleDateString();
        } catch {
            return dateStr;
        }
    }

    // ── API calls ──
    async function fetchSessions() {
        try {
            const res = await fetch('/api/chat/sessions', { credentials: 'same-origin' });
            if (!res.ok) return;
            const data = await res.json();
            sessions = data.sessions || [];
        } catch (err) {
            console.error('Failed to fetch sessions:', err);
        }
    }

    async function createSession() {
        try {
            const res = await fetch('/api/chat/sessions', { method: 'POST', credentials: 'same-origin' });
            if (!res.ok) return null;
            const data = await res.json();
            return data.session;
        } catch (err) {
            console.error('Failed to create session:', err);
            return null;
        }
    }

    async function deleteSession(id) {
        try {
            await fetch('/api/chat/sessions/' + encodeURIComponent(id), { method: 'DELETE', credentials: 'same-origin' });
        } catch (err) {
            console.error('Failed to delete session:', err);
        }
    }

    // ── Rendering ──
    function renderList() {
        if (!listEl) return;
        if (sessions.length === 0) {
            listEl.innerHTML = `<div class="session-empty">${escapeHtml(t('chat.sessions_empty'))}</div>`;
            return;
        }
        listEl.innerHTML = sessions.map(s => {
            const isActive = s.id === activeSessionId;
            const preview = s.preview || t('chat.sessions_no_preview');
            const timeAgo = formatTimeAgo(s.last_active_at);
            return `
                <div class="session-item${isActive ? ' session-active' : ''}" data-session-id="${escapeAttr(s.id)}">
                    <div class="session-item-content">
                        <div class="session-item-preview">${escapeHtml(preview)}</div>
                        <div class="session-item-meta">
                            <span class="session-item-time">${escapeHtml(timeAgo)}</span>
                            ${s.message_count > 0 ? `<span class="session-item-count">${s.message_count}</span>` : ''}
                        </div>
                    </div>
                    ${!isActive ? `<button class="session-item-delete" data-delete-id="${escapeAttr(s.id)}" title="${escapeAttr(t('chat.sessions_delete'))}">${window.chatUiIconMarkup ? window.chatUiIconMarkup('close') : ''}</button>` : ''}
                </div>`;
        }).join('');

        // Bind click events
        listEl.querySelectorAll('.session-item').forEach(el => {
            el.addEventListener('click', (e) => {
                // Ignore if clicking delete button
                if (e.target.closest('.session-item-delete')) return;
                const id = el.dataset.sessionId;
                if (id && id !== activeSessionId) {
                    switchSession(id);
                }
                close();
            });
        });

        listEl.querySelectorAll('.session-item-delete').forEach(btn => {
            btn.addEventListener('click', async (e) => {
                e.stopPropagation();
                const id = btn.dataset.deleteId;
                if (id) {
                    await deleteSession(id);
                    await fetchSessions();
                    renderList();
                }
            });
        });
    }

    // ── Session switching ──
    async function switchSession(sessionId) {
        activeSessionId = sessionId;
        localStorage.setItem('aurago-session-id', sessionId);

        // Notify main.js to reload chat for the new session
        if (typeof window.onSessionSwitch === 'function') {
            window.onSessionSwitch(sessionId);
        }
    }

    // ── New session ──
    async function handleNewSession() {
        const sess = await createSession();
        if (sess) {
            activeSessionId = sess.id;
            localStorage.setItem('aurago-session-id', sess.id);
            if (typeof window.onSessionSwitch === 'function') {
                window.onSessionSwitch(sess.id);
            }
            await fetchSessions();
            renderList();
            close();
        }
    }

    // ── Open / Close ──
    function open() {
        if (!drawer) return;
        isOpen = true;
        drawer.classList.add('open');
        backdrop.classList.add('active');
        if (toggleBtn) toggleBtn.setAttribute('aria-expanded', 'true');
        fetchSessions().then(renderList);
    }

    function close() {
        if (!drawer) return;
        isOpen = false;
        drawer.classList.remove('open');
        backdrop.classList.remove('active');
        if (toggleBtn) toggleBtn.setAttribute('aria-expanded', 'false');
    }

    function toggle() {
        if (isOpen) close();
        else open();
    }

    // ── Ghost session guard ──
    // Validate that the stored session ID still exists on the server.
    // If it was rotated or deleted, fall back to "default".
    async function validateStoredSession() {
        if (activeSessionId === 'default') return;
        try {
            const res = await fetch('/api/chat/sessions/' + encodeURIComponent(activeSessionId), { credentials: 'same-origin' });
            if (!res.ok) {
                // Session no longer exists – fall back
                activeSessionId = 'default';
                localStorage.setItem('aurago-session-id', 'default');
                return;
            }
            const data = await res.json();
            if (!data.session) {
                activeSessionId = 'default';
                localStorage.setItem('aurago-session-id', 'default');
            }
        } catch (_) {
            // Network error – keep current, don't block init
        }
    }

    // ── Init ──
    function init() {
        if (toggleBtn) {
            toggleBtn.addEventListener('click', toggle);
        }
        if (closeBtn) {
            closeBtn.addEventListener('click', close);
        }
        if (backdrop) {
            backdrop.addEventListener('click', close);
        }
        if (newBtn) {
            newBtn.addEventListener('click', handleNewSession);
        }
        // Validate stored session on page load
        validateStoredSession();
    }

    // ── Public API ──
    return {
        init,
        open,
        close,
        toggle,
        getActiveSessionId: () => activeSessionId,
        setActiveSessionId: (id) => {
            activeSessionId = id;
            localStorage.setItem('aurago-session-id', id);
        },
        refresh: () => fetchSessions().then(renderList),
    };
})();

