/* ui/js/chat/modules/integrations-drawer.js */
/* ── Integrations Drawer Module ───────────────────────────────────────────── */

window.IntegrationsDrawer = (function () {
    'use strict';

    let isOpen = false;
    let webhosts = [];
    let webhostsFetchPromise = null;
    let webhostsLoadedAt = 0;
    let lastFetchFailed = false;
    const WEBHOSTS_CACHE_TTL_MS = 30000;

    const drawer = document.getElementById('integrations-drawer');
    const backdrop = document.getElementById('integrations-backdrop');
    const listEl = document.getElementById('integrations-list');
    const toggleBtn = document.getElementById('integrations-toggle-btn');
    const closeBtn = document.getElementById('integrations-drawer-close');

    function t(key) {
        return typeof I18N !== 'undefined' && I18N[key] ? I18N[key] : key;
    }

    function escapeHtml(str) {
        const div = document.createElement('div');
        div.textContent = str || '';
        return div.innerHTML;
    }

    function escapeAttr(str) {
        return String(str || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/'/g, '&#39;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    }

    function hasFreshWebhosts() {
        return webhostsLoadedAt > 0 && Date.now() - webhostsLoadedAt < WEBHOSTS_CACHE_TTL_MS;
    }

    function showLoadingState() {
        if (!listEl) return;
        listEl.innerHTML = `<div class="integrations-empty">${escapeHtml(t('chat.integrations_loading'))}</div>`;
    }

    function showErrorState() {
        if (!listEl) return;
        listEl.innerHTML = `<div class="integrations-empty">${escapeHtml(t('chat.integrations_error'))}</div>`;
    }

    async function fetchWebhosts(options = {}) {
        const force = options.force === true;
        const showLoading = options.showLoading !== false;

        if (!force && hasFreshWebhosts()) {
            if (isOpen) renderList();
            return webhosts;
        }
        if (!force && webhostsFetchPromise) {
            if (showLoading && isOpen) showLoadingState();
            return webhostsFetchPromise;
        }

        if (showLoading && isOpen) showLoadingState();

        webhostsFetchPromise = (async () => {
            const res = await fetch('/api/integrations/webhosts', { credentials: 'same-origin', cache: 'no-store' });
            if (!res.ok) throw new Error(`HTTP ${res.status}`);
            const data = await res.json();
            webhosts = Array.isArray(data.webhosts) ? data.webhosts : [];
            webhostsLoadedAt = Date.now();
            lastFetchFailed = false;
            if (isOpen) renderList();
            return webhosts;
        })().catch((err) => {
            console.error('Failed to fetch integrations:', err);
            webhosts = [];
            webhostsLoadedAt = 0;
            lastFetchFailed = true;
            if (isOpen) showErrorState();
            return webhosts;
        }).finally(() => {
            webhostsFetchPromise = null;
        });

        return webhostsFetchPromise;
    }

    function renderList() {
        if (!listEl) return;
        if (!webhosts.length) {
            listEl.innerHTML = `<div class="integrations-empty">${escapeHtml(t('chat.integrations_empty'))}</div>`;
            return;
        }
        listEl.innerHTML = webhosts.map(item => {
            const status = item.status || 'starting';
            const url = item.url || '';
            return `
                <div class="integration-item" data-integration-id="${escapeAttr(item.id)}">
                    <div class="integration-icon">${window.chatUiIconMarkup ? window.chatUiIconMarkup(item.icon || 'web') : ''}</div>
                    <div class="integration-main">
                        <div class="integration-name">${escapeHtml(item.name || item.id)}</div>
                        <div class="integration-meta">
                            <span class="integration-status ${escapeAttr(status)}" aria-hidden="true"></span>
                            <span class="integration-url">${escapeHtml(url)}</span>
                        </div>
                    </div>
                    ${url ? `<a class="integration-open" href="${escapeAttr(url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(t('chat.integrations_open'))}</a>` : ''}
                </div>`;
        }).join('');
    }

    function open() {
        if (!drawer) return;
        isOpen = true;
        drawer.classList.add('open');
        if (backdrop) backdrop.classList.add('active');
        if (toggleBtn) toggleBtn.setAttribute('aria-expanded', 'true');
        if (hasFreshWebhosts()) {
            renderList();
        } else if (webhostsFetchPromise) {
            showLoadingState();
        } else {
            fetchWebhosts({ force: lastFetchFailed });
        }
    }

    function close() {
        if (!drawer) return;
        isOpen = false;
        drawer.classList.remove('open');
        if (backdrop) backdrop.classList.remove('active');
        if (toggleBtn) toggleBtn.setAttribute('aria-expanded', 'false');
    }

    function toggle() {
        if (isOpen) close();
        else open();
    }

    if (toggleBtn) toggleBtn.addEventListener('click', toggle);
    if (closeBtn) closeBtn.addEventListener('click', close);
    if (backdrop) backdrop.addEventListener('click', close);
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape' && isOpen) close();
    });

    function prefetchWebhosts() {
        fetchWebhosts({ showLoading: false });
    }

    function scheduleWebhostsPrefetch() {
        if (!drawer || !listEl) return;
        const runPrefetch = () => prefetchWebhosts();
        if (typeof window.requestIdleCallback === 'function') {
            window.requestIdleCallback(runPrefetch, { timeout: 1200 });
        } else {
            window.setTimeout(runPrefetch, 250);
        }
    }

    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', scheduleWebhostsPrefetch, { once: true });
    } else {
        scheduleWebhostsPrefetch();
    }

    return {
        open,
        close,
        refresh: () => fetchWebhosts({ force: true, showLoading: isOpen })
    };
})();

